/**
 * Runs the full 4-step SYSCOHADA year-end closing routine: (1) generate and auto-validate pending depreciation dotations and financial installments, (2) compute net result from Class 6/7 balances and post the clearing entry to account 1301 (bénéfice) or 1309 (perte), (3) lock the period so no further ledger entries are accepted for this client/year, (4) generate the Journal des À-nouveaux carrying forward Class 1-5 balances to year+1. Restricted to expert_comptable.
 * @summary Lock a fiscal year (Clôturer définitivement)
 */
export const ClosePeriodParams = zod.object({
  "clientId": zod.coerce.number(),
  "year": zod.coerce.number()
})

